class Solution {
public:
    vector<bool> canMakePalindromeQueries(string s, vector<vector<int>>& queries) {
        int n = s.size();
        vector<int> counts(26, 0);
        for (int i = 0; i < n / 2; i++) {
            counts[s[i] - 'a']++;
            counts[s[n - 1 - i] - 'a']--;
        }
        vector<int> prefix(26, 0);
        for (int i = 0; i < 26; i++) {
            prefix[i] = counts[i];
            if (i > 0) prefix[i] += prefix[i - 1];
        }
        vector<bool> result;
        for (auto& query : queries) {
            int a = query[0], b = query[1], c = query[2], d = query[3];
            int left_diff = 0;
            for (int i = a; i <= b; i++) {
                left_diff += (s[i] - 'a' >= 0 && s[i] - 'a' <= 25) ? 1 : 0;
                left_diff -= (s[b - i + a] - 'a' >= 0 && s[b - i + a] - 'a' <= 25) ? 1 : 0;
            }
            int right_diff = 0;
            for (int i = c; i <= d; i++) {
                right_diff += (s[i] - 'a' >= 0 && s[i] - 'a' <= 25) ? 1 : 0;
                right_diff -= (s[n - 1 - i + c] - 'a' >= 0 && s[n - 1 - i + c] - 'a' <= 25) ? 1 : 0;
            }
            bool possible = (left_diff == 0 && right_diff == 0) ||
                            (abs(left_diff) % 2 == 0 && abs(right_diff) % 2 == 0 && 
                             (prefix[25] - (left_diff > 0 ? prefix[left_diff - 1] : 0) - (right_diff > 0 ? prefix[right_diff - 1] : 0)) >= 0);
            result.push_back(possible);
        }
        return result;
    }
};
